    int longestPalindrome(string s, string t) {
        int n = s.size(), m = t.size();
        vector<vector<int>> dp1(n + 1, vector<int>(n + 1, 0));
        vector<vector<int>> dp2(m + 1, vector<int>(m + 1, 0));

        for (int i = n - 1; i >= 0; i--) {
            for (int j = i; j < n; j++) {
                if (s[i] == s[j] && (j - i < 2 || dp1[i + 1][j - 1])) {
                    dp1[i][j] = j - i + 1;
                }
            }
        }

        for (int i = m - 1; i >= 0; i--) {
            for (int j = i; j < m; j++) {
                if (t[i] == t[j] && (j - i < 2 || dp2[i + 1][j - 1])) {
                    dp2[i][j] = j - i + 1;
                }
            }
        }

        int res = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                res = max(res, dp1[0][i] + dp2[0][j]);
            }
        }

        return res;
    }
};
